双指针算法 最长不连续重复子序列 #include &lt;iostream&gt; using namespace std; const int N = 100010; int a[N], s[N]; int main() { int n; cin &gt;&gt; n; int res = 0; for (int i = 0; i &lt; n; i ++) cin &gt;&gt; a[i]; for (int i = 0, j = 0; i &lt; n; i ++) { s[a[i]] ++; while (s[a[i]] &gt; 1) { s[a[j]] --; j ++; } res = max(res, i - j + 1); } cout &lt;&lt; res; return 0; } 数组元素的目标和 #include &lt;iostream&gt; using namespace std; const int N = 100010; int n, m, x; int a[N], b[N]; int main() { cin &gt;&gt; n &gt;&gt; m &gt;&gt; x; for (int i = 0; i &lt; n; i ++) cin &gt;&gt; a[i]; for (int j = 0; j &lt; m; j ++) cin &gt;&gt; b[j]; for (int i = 0, j = m - 1; i &lt; n; i ++) { while (j &gt;= 0 &amp;&amp; a[i] + b[j] &gt; x) j --; if (a[i] + b[j] == x) { printf(&#34;%d %d\n&#34;, i, j); break; } } return 0; } 位运算 二进制中1的个数 #include &lt;iostream&gt; using namespace std; int lowbit(int x) { return x &amp; -x; } int main() { int n; cin &gt;&gt; n; while (n --) { int m; cin &gt;&gt; m; int res = 0; while (m) { m -= lowbit(m); res += 1; } cout &lt;&lt; res &lt;&lt; &#39; &#39;; } return 0; } 64位整数乘法 求 a 乘 b 对 p 取模的值。
输入格式 第一行输入整数 a ，第二行输入整数 b ，第三行输入整数 p 。
输出格式 输出一个整数，表示a*b mod p的值。
数据范围 1≤a,b,p≤1018 输入样例： 3 4 5 输出样例： 2
#include &lt;iostream&gt;#define ll long long  using namespace std; int main() { ll a, b, p, res = 0; cin &gt;&gt; a &gt;&gt; b &gt;&gt; p; while (b) { if (b &amp; 1) res = (res + a) % p; //判断最后一位是否为1，如果是1，那么在加法分配律里应该乘的是1不是0；  //每一步循环的操作是加上再对p求模。  b &gt;&gt;= 1; a = a * 2 % p; } cout &lt;&lt; res &lt;&lt; endl; return 0; } 区间和（离散化） #include &lt;iostream&gt;#include &lt;vector&gt;#include &lt;algorithm&gt; using namespace std; const int N = 300010; int a[N], s[N]; vector&lt;int&gt; alls; typedef pair&lt;int, int&gt; PII; vector&lt;PII&gt; add, query; int find(int x) { int l = 1, r = alls.size(); while (l &lt; r) { int mid = l + r &gt;&gt; 1; if (alls[mid] &gt;= x) r = mid; else l = mid + 1; } return r; //return lower_bound(alls.begin, alls.end(), x) - alls.begin() + 1; } int main() { int n, m; cin &gt;&gt; n &gt;&gt; m; for (int i = 0; i &lt; n; i ++) { int x, c; cin &gt;&gt; x &gt;&gt; c; add.push_back({x, c}); alls.push_back(x); } for (int i = 0; i &lt; m; i ++) { int l, r; cin &gt;&gt; l &gt;&gt; r; query.push_back({l, r}); alls.push_back(l); alls.push_back(r); } sort(alls.begin(), alls.end()); alls.erase(unique(alls.begin(), alls.end()), alls.end()); for (auto item : add) { int x = find(item.first); a[x] += item.second; } for (int i = 1; i &lt;= alls.size(); i ++) s[i] = s[i - 1] + a[i]; for (auto item : query) { int l = find(item.first), r = find(item.second); cout &lt;&lt; s[r] - s[l - 1] &lt;&lt; endl; } return 0; } #include &lt;iostream&gt;#include &lt;vector&gt;#include &lt;algorithm&gt; using namespace std; typedef pair&lt;int, int&gt; PII; //操作，有两个数。  const int N = 300010; int n, m; int a[N], s[N]; //a数组是存插入后该坐标的值，s数组是前缀和。  vector&lt;int&gt; alls; //存入的所有要离散化的值。 vector&lt;PII&gt; add, query; //插入和查询都需要两个数，所以用pair  //找原本的坐标离散化后的值 int find(int x) { int l = 0, r = alls.size() - 1; while (l &lt; r) { int mid = l + r &gt;&gt; 1; if (alls[mid] &gt;= x) r = mid; else l = mid + 1; } return r + 1; //因为要用到前缀和，所以映射到从1开始的自然数。 } int main() { int n, m; cin &gt;&gt; n &gt;&gt; m; //先把所有需要操作的数读进来。（n次操作）  for (int i = 0; i &lt; n; i ++) { int x, c; cin &gt;&gt; x &gt;&gt; c; add.push_back({x, c}); //对x位置加上c；  alls.push_back(x); } for (int i = 0; i &lt; m; i ++) { int l, r; cin &gt;&gt; l &gt;&gt; r; query.push_back({l, r}); //查询l和r  alls.push_back(l); alls.push_back(r); } //去重  sort(alls.begin(), alls.end()); alls.erase(unique(alls.begin(), alls.end()), alls.end()); //处理插入  for (auto item : add) { int x = find(item.first); //求离散化后的值  a[x] += item.second; } //预处理前缀和  for (int i = 1; i &lt;= alls.size(); i ++) s[i] = s[i - 1] + a[i]; //处理询问  for (auto item : query) { int l = find(item.first), r = find(item.second); cout &lt;&lt; s[r] - s[l - 1] &lt;&lt; endl; } } vector&lt;int&gt;::iterator unique(vector&lt;int&gt; &amp;a) { int j = 0; for (int i = 0; i &lt; a.size(); i ++) if (!i || a[i] != a[i - 1]) a[j ++] = a[i]; //a[0] ~ a[j - 1]所有a中不重复的数  return a.begin() + j; } unique函数的实现
