#include &lt;iostream&gt;#include &lt;vector&gt;#include &lt;algorithm&gt; using namespace std; typedef pair&lt;int, int&gt; PII; vector&lt;PII&gt; segs; void merge(vector&lt;PII&gt; &amp;segs) { int st = -2e9, ed = -2e9; vector&lt;PII&gt; res; sort(segs.begin(), segs.end()); //忘记排序好多次  for (auto seg : segs) { if (ed &lt; seg.first) { if (st != -2e9) res.push_back({st, ed}); //pair忘记加大括号好多次  st = seg.first, ed = seg.second; //second, first后面不用加括号  } else ed = max(ed, seg.second); } if (st != -2e9) res.push_back({st, ed}); segs = res; } int main() { int n; cin &gt;&gt; n; while (n --) { int l, r; cin &gt;&gt; l &gt;&gt; r; segs.push_back({l, r}); } merge(segs); cout &lt;&lt; segs.size() &lt;&lt; endl; return 0; }

双指针算法 思路：先写一个暴力n*n的算法，然后看i和j有没有什么单调关系，有单调关系的话可以把枚举的状态数量从O（n*n)变成O（n）。
